// lib/firebase-admin.ts
import admin from "firebase-admin";
import { readFileSync } from "fs";
import path from "path";

if (!admin.apps.length) {
  const serviceAccountPath = path.resolve(
    process.cwd(),
    "lib/firebase-admin/serviceAccountKey.json"
  );

  const serviceAccount = JSON.parse(readFileSync(serviceAccountPath, "utf8"));

  admin.initializeApp({
    credential: admin.credential.cert(serviceAccount),
    databaseURL: "https://novawebstudio-b7489-default-rtdb.firebaseio.com",
  });
}

export const db = admin.database(); // Realtime Database
export const auth = admin.auth();
export const firestore = admin.firestore(); // si usas Firestore
